// Generates app/public/THIRD-PARTY-NOTICES.txt — license notices for the
// third-party runtime dependencies that end up in the deployed JS bundle
// (window bundle + service worker). Deterministic: same deps in, same file
// out — so the generated file is committed and only regenerated on dependency
// bumps via `npm --prefix app run notices` (deliberately NOT wired into the
// build).
//
// Scope: runtime deps only. Dev/build-time tooling (vite, vitest, eslint,
// playwright, ...) never ships to users and is not listed here.
import { readdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

import { copyrightHolder } from './copyright-holder.mjs';

const APP_ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');

// Runtime packages bundled into the deployed app:
// - maplibre-gl, pmtiles, @protomaps/basemaps — map rendering stack
// - react, react-dom — UI framework
// - idb — IndexedDB persistence wrapper
// - workbox-core/-precaching/-range-requests/-routing — imported by src/sw.ts
// - workbox-window — pulled into the window bundle by vite-plugin-pwa's
//   virtual:pwa-register/react wiring
const PACKAGES = [
  '@protomaps/basemaps',
  'idb',
  'maplibre-gl',
  'pmtiles',
  'react',
  'react-dom',
  'workbox-core',
  'workbox-precaching',
  'workbox-range-requests',
  'workbox-routing',
  'workbox-window',
];

const HEADER = `THIRD-PARTY NOTICES for SailCommand
====================================

SailCommand's deployed JavaScript bundle includes the open-source packages
listed below. Their license and copyright notices are reproduced here as
required by their respective licenses. This file covers only the runtime
code shipped to the browser; the SailCommand application code itself is
licensed under the Apache License 2.0 (see the repository LICENSE file), and
map/bathymetry/wind DATA carry their own attributions (see the README and
the in-app About dialog).

Generated by app/scripts/gen-third-party-notices.mjs
(regenerate with: npm --prefix app run notices).
`;

// Assumptions (re-check when adding a package to PACKAGES):
// - first match wins: candidates are sorted and only [0] is read, so a
//   dual-licensed package shipping e.g. LICENSE-APACHE + LICENSE-MIT would
//   emit only the first alphabetical file;
// - matches are assumed to be FILES: a directory named licenses/ would match
//   the pattern and make the subsequent readFileSync fail with EISDIR.
function findLicenseFile(pkgDir) {
  const candidates = readdirSync(pkgDir)
    .filter((name) => /^licen[cs]e/i.test(name))
    .sort();
  return candidates.length > 0 ? join(pkgDir, candidates[0]) : null;
}

// Canonical SPDX license texts, used when a package declares a license in
// package.json but does not bundle the text in its npm tarball. The
// {{holder}} placeholder is filled from the package's author field.
const LICENSE_TEMPLATES = {
  'BSD-3-Clause': `BSD 3-Clause License

Copyright (c) {{holder}}
All rights reserved.

Redistribution and use in source and binary forms, with or without
modification, are permitted provided that the following conditions are met:

1. Redistributions of source code must retain the above copyright notice, this
   list of conditions and the following disclaimer.

2. Redistributions in binary form must reproduce the above copyright notice,
   this list of conditions and the following disclaimer in the documentation
   and/or other materials provided with the distribution.

3. Neither the name of the copyright holder nor the names of its
   contributors may be used to endorse or promote products derived from
   this software without specific prior written permission.

THIS SOFTWARE IS PROVIDED BY THE COPYRIGHT HOLDERS AND CONTRIBUTORS "AS IS"
AND ANY EXPRESS OR IMPLIED WARRANTIES, INCLUDING, BUT NOT LIMITED TO, THE
IMPLIED WARRANTIES OF MERCHANTABILITY AND FITNESS FOR A PARTICULAR PURPOSE ARE
DISCLAIMED. IN NO EVENT SHALL THE COPYRIGHT HOLDER OR CONTRIBUTORS BE LIABLE
FOR ANY DIRECT, INDIRECT, INCIDENTAL, SPECIAL, EXEMPLARY, OR CONSEQUENTIAL
DAMAGES (INCLUDING, BUT NOT LIMITED TO, PROCUREMENT OF SUBSTITUTE GOODS OR
SERVICES; LOSS OF USE, DATA, OR PROFITS; OR BUSINESS INTERRUPTION) HOWEVER
CAUSED AND ON ANY THEORY OF LIABILITY, WHETHER IN CONTRACT, STRICT LIABILITY,
OR TORT (INCLUDING NEGLIGENCE OR OTHERWISE) ARISING IN ANY WAY OUT OF THE USE
OF THIS SOFTWARE, EVEN IF ADVISED OF THE POSSIBILITY OF SUCH DAMAGE.`,
  MIT: `MIT License

Copyright (c) {{holder}}

Permission is hereby granted, free of charge, to any person obtaining a copy
of this software and associated documentation files (the "Software"), to deal
in the Software without restriction, including without limitation the rights
to use, copy, modify, merge, publish, distribute, sublicense, and/or sell
copies of the Software, and to permit persons to whom the Software is
furnished to do so, subject to the following conditions:

The above copyright notice and this permission notice shall be included in all
copies or substantial portions of the Software.

THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR
IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,
FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE
AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER
LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,
OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE
SOFTWARE.`,
};

// Copyright-holder resolution (verified overrides + sanitized author field)
// lives in copyright-holder.mjs so it stays unit-testable (#69).

function packageBlock(pkgName) {
  const pkgDir = join(APP_ROOT, 'node_modules', pkgName);
  const pkg = JSON.parse(readFileSync(join(pkgDir, 'package.json'), 'utf8'));
  const separator = '-'.repeat(72);
  const title = `${pkg.name} ${pkg.version} — license: ${pkg.license}`;

  const licenseFile = findLicenseFile(pkgDir);
  let body;
  if (licenseFile) {
    body = readFileSync(licenseFile, 'utf8').replace(/\r\n/g, '\n').trimEnd();
  } else {
    // Some packages (e.g. pmtiles, @protomaps/basemaps) declare an SPDX
    // license in package.json but do not bundle the license text in the npm
    // tarball. Reproduce the canonical license text with the package's
    // copyright holder, and record where to find the project.
    const repo =
      typeof pkg.repository === 'string' ? pkg.repository : pkg.repository?.url;
    const home = pkg.homepage ?? repo;
    const template = LICENSE_TEMPLATES[pkg.license];
    if (!template) {
      throw new Error(
        `${pkg.name}: no bundled license text and no ${pkg.license} template — ` +
          'add the canonical text to LICENSE_TEMPLATES.',
      );
    }
    body =
      `(The npm package does not bundle its license text; the canonical\n` +
      `${pkg.license} text is reproduced below.` +
      (home ? ` Project: ${home}` : '') +
      `)\n\n` +
      template.replace('{{holder}}', copyrightHolder(pkg));
  }
  return `${separator}\n${title}\n${separator}\n\n${body}\n`;
}

const output = [HEADER, ...PACKAGES.map(packageBlock)].join('\n');
writeFileSync(join(APP_ROOT, 'public', 'THIRD-PARTY-NOTICES.txt'), output);
console.log(
  `wrote app/public/THIRD-PARTY-NOTICES.txt (${PACKAGES.length} packages)`,
);
